SELECT AVG(score) AS average_score
FROM test_runs
WHERE run_by = 1;

SELECT test_run_id
FROM test_runs
ORDER BY test_run_id;

SELECT run_date
FROM test_runs
ORDER BY run_date DESC;

SELECT MAX(access_date)
FROM test_run_access_logs
WHERE test_run_id = 1;

SELECT MAX(access_date) AS latest_access_date
FROM benchmark_access_logs
WHERE benchmark_id = 1;
